import{_ as s,o as n,c as e,a2 as p}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"DeerFlow Architecture","description":"","frontmatter":{"title":"DeerFlow Architecture","status":"complete"},"headers":[],"relativePath":"research/agents/deer-flow/architecture.md","filePath":"research/agents/deer-flow/architecture.md"}'),t={name:"research/agents/deer-flow/architecture.md"};function l(o,a,r,c,i,d){return n(),e("div",null,[...a[0]||(a[0]=[p(`<h1 id="deerflow-architecture" tabindex="-1">DeerFlow Architecture <a class="header-anchor" href="#deerflow-architecture" aria-label="Permalink to &quot;DeerFlow Architecture&quot;">​</a></h1><h2 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th><th>Notes</th></tr></thead><tbody><tr><td>Orchestration</td><td>LangGraph</td><td>Graph-based state machines; checkpointing, time-travel</td></tr><tr><td>LLM Abstraction</td><td>LangChain</td><td>Any OpenAI-compatible endpoint</td></tr><tr><td>Backend</td><td>Python 3.12+</td><td>FastAPI + LangGraph Server</td></tr><tr><td>Frontend</td><td>Next.js / Node.js 22+</td><td>pnpm, served on port 3000</td></tr><tr><td>Package Manager (backend)</td><td>uv</td><td>Fast Python package management</td></tr><tr><td>Package Manager (frontend)</td><td>pnpm</td><td>Node.js</td></tr><tr><td>Container / Sandbox</td><td>Docker</td><td>Isolated per-task execution environment</td></tr><tr><td>Orchestration (advanced)</td><td>Kubernetes</td><td>Via provisioner service for K8s sandbox mode</td></tr></tbody></table><hr><h2 id="service-architecture" tabindex="-1">Service Architecture <a class="header-anchor" href="#service-architecture" aria-label="Permalink to &quot;Service Architecture&quot;">​</a></h2><p>DeerFlow runs as multiple services, typically via Docker Compose or local dev scripts. A unified reverse proxy (nginx, port 2026) routes traffic:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Port 2026 (nginx unified proxy)</span></span>
<span class="line"><span>├── /                    → Next.js frontend (port 3000)</span></span>
<span class="line"><span>├── /api/langgraph/      → LangGraph Server (port 2024)</span></span>
<span class="line"><span>└── /api/gateway/        → Gateway API (port 8001)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Port 2024 — LangGraph Server</span></span>
<span class="line"><span>  └── Hosts the agent graph (lead_agent, mobile_agent, etc.)</span></span>
<span class="line"><span>  └── Runs via \`langgraph dev\` (open-source LangGraph CLI server)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Port 8001 — Gateway API</span></span>
<span class="line"><span>  └── Skill installation endpoint</span></span>
<span class="line"><span>  └── Follow-up suggestion generation</span></span>
<span class="line"><span>  └── IM channel dispatch (Telegram, Slack, Feishu)</span></span>
<span class="line"><span>  └── Health checks, model listing, thread management</span></span></code></pre></div><hr><h2 id="agent-graph-langgraph" tabindex="-1">Agent Graph (LangGraph) <a class="header-anchor" href="#agent-graph-langgraph" aria-label="Permalink to &quot;Agent Graph (LangGraph)&quot;">​</a></h2><p>The lead agent is a <strong>typed state graph</strong> implemented in LangGraph. Each node is a Python function operating on the shared state:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>                  ┌─────────────────┐</span></span>
<span class="line"><span>    ┌────────────►│  coordinator    │◄──────────────┐</span></span>
<span class="line"><span>    │             └────────┬────────┘               │</span></span>
<span class="line"><span>    │                      │ (delegate task)         │</span></span>
<span class="line"><span>    │             ┌────────▼────────┐               │</span></span>
<span class="line"><span>    │             │  planner        │ (pro/ultra     │</span></span>
<span class="line"><span>    │             └────────┬────────┘  modes only)   │</span></span>
<span class="line"><span>    │                      │                         │</span></span>
<span class="line"><span>    │             ┌────────▼────────┐               │</span></span>
<span class="line"><span>    │             │  researcher     │               │</span></span>
<span class="line"><span>    │             │  (web search,   │               │</span></span>
<span class="line"><span>    │             │   web fetch,    │               │</span></span>
<span class="line"><span>    │             │   bash, files)  │               │</span></span>
<span class="line"><span>    │             └────────┬────────┘               │</span></span>
<span class="line"><span>    │                      │ spawn sub-agents        │</span></span>
<span class="line"><span>    │             ┌────────▼────────┐               │</span></span>
<span class="line"><span>    │             │  sub_agent_1    │               │</span></span>
<span class="line"><span>    │             │  sub_agent_2    │ (ultra mode)   │</span></span>
<span class="line"><span>    │             │  sub_agent_N    │               │</span></span>
<span class="line"><span>    │             └────────┬────────┘               │</span></span>
<span class="line"><span>    │                      │ structured results      │</span></span>
<span class="line"><span>    │             ┌────────▼────────┐               │</span></span>
<span class="line"><span>    │             │  reporter       │               │</span></span>
<span class="line"><span>    │             │  (synthesis,    │               │</span></span>
<span class="line"><span>    │             │   output gen)   │               │</span></span>
<span class="line"><span>    │             └────────┬────────┘               │</span></span>
<span class="line"><span>    │                      │                         │</span></span>
<span class="line"><span>    └──────────────────────┴─────────────────────────┘</span></span>
<span class="line"><span>                     (loop if incomplete)</span></span></code></pre></div><p><strong>Key LangGraph features used:</strong></p><ul><li><strong>State checkpointing</strong> — durable execution; resume after failures</li><li><strong>Streaming</strong> — token-by-token output delivered to frontend via SSE</li><li><strong>Conditional edges</strong> — routing to planner only in pro/ultra modes</li><li><strong>Subgraph</strong> — each sub-agent is its own graph with isolated state</li></ul><hr><h2 id="sandbox-architecture" tabindex="-1">Sandbox Architecture <a class="header-anchor" href="#sandbox-architecture" aria-label="Permalink to &quot;Sandbox Architecture&quot;">​</a></h2><p>DeerFlow has three sandbox modes, selected in <code>config.yaml</code>:</p><h3 id="mode-1-local-execution" tabindex="-1">Mode 1: Local Execution <a class="header-anchor" href="#mode-1-local-execution" aria-label="Permalink to &quot;Mode 1: Local Execution&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">sandbox</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> deerflow.community.local_sandbox:LocalSandboxProvider</span></span></code></pre></div><p>Runs code directly on the host machine. Fastest, least isolated. Development/testing only.</p><h3 id="mode-2-docker-execution" tabindex="-1">Mode 2: Docker Execution <a class="header-anchor" href="#mode-2-docker-execution" aria-label="Permalink to &quot;Mode 2: Docker Execution&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">sandbox</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> deerflow.community.docker_sandbox:DockerSandboxProvider</span></span></code></pre></div><p>Each task session spins up a Docker container with a mounted filesystem:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>/mnt/skills/public/          ← Built-in skill Markdown files</span></span>
<span class="line"><span>├── research/SKILL.md</span></span>
<span class="line"><span>├── report-generation/SKILL.md</span></span>
<span class="line"><span>├── slide-creation/SKILL.md</span></span>
<span class="line"><span>├── web-page/SKILL.md</span></span>
<span class="line"><span>└── image-generation/SKILL.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/mnt/skills/custom/          ← User-defined skill Markdown files</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/mnt/user-data/</span></span>
<span class="line"><span>├── uploads/                 ← Files uploaded by the user</span></span>
<span class="line"><span>├── workspace/               ← Agent&#39;s working directory (read/write)</span></span>
<span class="line"><span>└── outputs/                 ← Final deliverables</span></span></code></pre></div><p><strong>Container lifecycle</strong>: Created at session start, destroyed at session end. State is persisted via the mounted <code>/mnt/user-data/</code> volume.</p><h3 id="mode-3-docker-kubernetes-provisioner" tabindex="-1">Mode 3: Docker + Kubernetes (Provisioner) <a class="header-anchor" href="#mode-3-docker-kubernetes-provisioner" aria-label="Permalink to &quot;Mode 3: Docker + Kubernetes (Provisioner)&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">sandbox</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> deerflow.community.aio_sandbox:AioSandboxProvider</span></span>
<span class="line"><span style="color:#89B4FA;">  provisioner_url</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> http://provisioner:8080</span></span></code></pre></div><p>Runs sandbox containers as Kubernetes Pods via a provisioner service. Enables multi-tenant deployments with resource isolation and scheduling.</p><hr><h2 id="model-configuration" tabindex="-1">Model Configuration <a class="header-anchor" href="#model-configuration" aria-label="Permalink to &quot;Model Configuration&quot;">​</a></h2><p>DeerFlow uses a <code>config.yaml</code>-based model registry rather than hardcoded providers. Any OpenAI-compatible endpoint works:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">models</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> gpt-4</span></span>
<span class="line"><span style="color:#89B4FA;">    display_name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> GPT-4</span></span>
<span class="line"><span style="color:#89B4FA;">    use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> langchain_openai:ChatOpenAI</span></span>
<span class="line"><span style="color:#89B4FA;">    model</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> gpt-4</span></span>
<span class="line"><span style="color:#89B4FA;">    api_key</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> $OPENAI_API_KEY</span></span>
<span class="line"><span style="color:#89B4FA;">    max_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 4096</span></span>
<span class="line"><span style="color:#89B4FA;">    temperature</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 0.7</span></span>
<span class="line"></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> openrouter-gemini</span></span>
<span class="line"><span style="color:#89B4FA;">    display_name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Gemini 2.5 Flash (OpenRouter)</span></span>
<span class="line"><span style="color:#89B4FA;">    use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> langchain_openai:ChatOpenAI</span></span>
<span class="line"><span style="color:#89B4FA;">    model</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> google/gemini-2.5-flash-preview</span></span>
<span class="line"><span style="color:#89B4FA;">    api_key</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> $OPENROUTER_API_KEY</span></span>
<span class="line"><span style="color:#89B4FA;">    base_url</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> https://openrouter.ai/api/v1</span></span></code></pre></div><p><strong>CLI-backed providers</strong> (v2 addition): DeerFlow can route through CLI tools rather than HTTP APIs:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">models</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> claude-sonnet-4.6</span></span>
<span class="line"><span style="color:#89B4FA;">    display_name</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> Claude Sonnet 4.6 (Claude Code OAuth)</span></span>
<span class="line"><span style="color:#89B4FA;">    use</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> deerflow.models.claude_provider:ClaudeChatModel</span></span>
<span class="line"><span style="color:#89B4FA;">    model</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> claude-sonnet-4-6</span></span>
<span class="line"><span style="color:#89B4FA;">    supports_thinking</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span></code></pre></div><p>This lets DeerFlow use Claude Code&#39;s OAuth credentials or Codex CLI&#39;s <code>~/.codex/auth.json</code> — enabling LLM access without separate API key management.</p><p><strong>Recommended models</strong> (ByteDance-promoted):</p><ul><li>Doubao-Seed-2.0-Code</li><li>DeepSeek v3.2</li><li>Kimi 2.5</li></ul><hr><h2 id="im-channel-architecture" tabindex="-1">IM Channel Architecture <a class="header-anchor" href="#im-channel-architecture" aria-label="Permalink to &quot;IM Channel Architecture&quot;">​</a></h2><p>DeerFlow&#39;s Gateway process handles IM channels. Each channel connects without requiring a public IP:</p><table tabindex="0"><thead><tr><th>Channel</th><th>Transport</th><th>Auth</th></tr></thead><tbody><tr><td>Telegram</td><td>Bot API (long-polling)</td><td>Bot token</td></tr><tr><td>Slack</td><td>Socket Mode</td><td>Bot token + App token</td></tr><tr><td>Feishu / Lark</td><td>WebSocket (Long Connection)</td><td>App ID + App Secret</td></tr></tbody></table><p>Channels auto-start when configured. They route messages to the LangGraph Server and stream responses back.</p><p>Per-channel and per-user session configuration allows different agent personas, execution modes, and recursion limits for different users/channels.</p><hr><h2 id="deployment-options" tabindex="-1">Deployment Options <a class="header-anchor" href="#deployment-options" aria-label="Permalink to &quot;Deployment Options&quot;">​</a></h2><h3 id="docker-compose-recommended" tabindex="-1">Docker Compose (Recommended) <a class="header-anchor" href="#docker-compose-recommended" aria-label="Permalink to &quot;Docker Compose (Recommended)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>make docker-init   # Pull sandbox image</span></span>
<span class="line"><span>make docker-start  # Start all services (auto-detects sandbox mode)</span></span>
<span class="line"><span>make up            # Production: build images + start</span></span>
<span class="line"><span>make down          # Stop and remove</span></span></code></pre></div><h3 id="local-development" tabindex="-1">Local Development <a class="header-anchor" href="#local-development" aria-label="Permalink to &quot;Local Development&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>make check         # Verify Node.js 22+, pnpm, uv, nginx</span></span>
<span class="line"><span>make install       # Install backend + frontend deps</span></span>
<span class="line"><span>make dev           # Start all services</span></span></code></pre></div><p>Access at <a href="http://localhost:2026" target="_blank" rel="noreferrer">http://localhost:2026</a> in both cases.</p><hr><h2 id="configuration-file-structure" tabindex="-1">Configuration File Structure <a class="header-anchor" href="#configuration-file-structure" aria-label="Permalink to &quot;Configuration File Structure&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>deer-flow/</span></span>
<span class="line"><span>├── config.yaml          ← Primary config (models, sandbox, channels)</span></span>
<span class="line"><span>├── .env                 ← API keys (not committed)</span></span>
<span class="line"><span>├── backend/</span></span>
<span class="line"><span>│   ├── pyproject.toml</span></span>
<span class="line"><span>│   └── src/deerflow/</span></span>
<span class="line"><span>│       ├── agents/      ← LangGraph agent graphs</span></span>
<span class="line"><span>│       ├── models/      ← Provider implementations</span></span>
<span class="line"><span>│       ├── community/   ← Sandbox providers</span></span>
<span class="line"><span>│       └── skills/      ← Skill loading logic</span></span>
<span class="line"><span>├── frontend/</span></span>
<span class="line"><span>│   ├── package.json</span></span>
<span class="line"><span>│   └── src/</span></span>
<span class="line"><span>└── skills/</span></span>
<span class="line"><span>    └── public/          ← Built-in SKILL.md files</span></span>
<span class="line"><span>        ├── research/</span></span>
<span class="line"><span>        ├── report-generation/</span></span>
<span class="line"><span>        └── claude-to-deerflow/</span></span></code></pre></div>`,52)])])}const m=s(t,[["render",l]]);export{u as __pageData,m as default};
